# Let me check if there are any hidden files or different locations where the attachment might be
import os
import glob

# Check all files including hidden ones
all_files = glob.glob('*') + glob.glob('.*')
print("All files (including hidden):", all_files)

# Check if there are any directories we should look in
for item in all_files:
    if os.path.isdir(item):
        print(f"Directory {item} contents:", os.listdir(item))

# Try to find files recursively
import fnmatch

def find_files(pattern, path):
    result = []
    for root, dirs, files in os.walk(path):
        for name in files:
            if fnmatch.fnmatch(name, pattern):
                result.append(os.path.join(root, name))
    return result

mp3_files = find_files('*.mp3', '.')
print("MP3 files found recursively:", mp3_files)

# Also try looking for the specific file
specific_file = '2b3ef98c-cc05-450b-a719-711aee40ac65.mp3'
