# Check if there are any symbolic links or special files
import stat
for item in all_files:
    try:
        file_stat = os.lstat(item)
        if stat.S_ISLNK(file_stat.st_mode):
            print(f"Symbolic link: {item} -> {os.readlink(item)}")
        elif not stat.S_ISREG(file_stat.st_mode) and not stat.S_ISDIR(file_stat.st_mode):
            print(f"Special file: {item} (mode: {stat.filemode(file_stat.st_mode)})")
    except (OSError, PermissionError):
        continue

