# Check if there are any processes running that might be related to audio processing
import subprocess

try:
    ps_result = subprocess.run(['ps', 'aux'], capture_output=True, text=True, timeout=10)
    print("Running processes (first few lines):")
    lines = ps_result.stdout.split('\n')[:10]
    for line in lines:
        print(line)
except Exception as e:
    print(f"Could not get process list: {e}")

# Let's also try to see if there are any installed packages related to audio
try:
    pip_result = subprocess.run(['pip', 'list'], capture_output=True, text=True, timeout=10)
    audio_related = []
    for line in pip_result.stdout.split('\n'):
        if any(keyword in line.lower() for keyword in ['audio', 'sound', 'speech', 'librosa', 'pydub']):
            audio_related.append(line)
    print("Audio-related packages:")
    for package in audio_related:
        print(package)
except Exception as e:
    print(f"Could not get package list: {e}")

